const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const SRC = path.join(PROJECT, 'src');

// Collect all agent outputs and extract file blocks
const agents = [
  'Gen Tokens',
  'Gen Primitives',
  'Gen Sidebar',
  'Gen Main Area',
  'Gen Viewport',
];

const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const results = {};
let filesWritten = 0;

for (const agentName of agents) {
  try {
    const output = $(agentName).item.json.output || '';
    let match;
    const regex = new RegExp(fileRegex.source, fileRegex.flags);
    while ((match = regex.exec(output)) !== null) {
      const filePath = match[1];
      const content = match[2].trim();
      const fullPath = path.join(PROJECT, filePath);

      // Ensure directory exists
      const dir = path.dirname(fullPath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

      fs.writeFileSync(fullPath, content);
      results[filePath] = `WRITTEN (${content.length} chars)`;
      filesWritten++;
    }
    if (!output.match(fileRegex)) {
      results[agentName] = 'NO FILE BLOCKS FOUND';
    }
  } catch (e) {
    results[agentName] = `ERROR: ${e.message}`;
  }
}

// Run TSC check
let tscResult = '';
try {
  tscResult = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 120000 }).toString();
  if (!tscResult.trim()) tscResult = 'OK - no errors';
} catch (e) {
  tscResult = e.stdout?.toString() || e.message;
}

return [{ json: { filesWritten, results, tscResult } }];

const { execSync } = require('child_process');
const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';

const tsc = $json.tscResult || '';
let gitResult = '';

if (tsc.includes('OK - no errors') || !tsc.includes('error TS')) {
  try {
    execSync('git add -A', { cwd: PROJECT });
    execSync(`git commit -m "style: ground-up UI/UX redesign — new tokens, primitives, layout\n\nApplied comprehensive design token system.\nUpdated all 7 UI primitives with size variants and states.\nRedesigned sidebar: collapsible sections, compact spacing.\nNew 3-column grid layout with resizable panels.\nChart components use new color palette.\nViewport overlay toolbar added."`, { cwd: PROJECT });
    execSync('git push origin main', { cwd: PROJECT });
    gitResult = 'Committed and pushed';
  } catch (e) {
    gitResult = `Git error: ${e.message}`;
  }
} else {
  gitResult = 'Skipped commit — TSC errors found';
}

return [{ json: { ...$json, gitResult } }];
